#include <stdio.h>
#include <stdlib.h>
int compare(const void *a, const void *b) { return (*(int*)a - *(int*)b); }
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, K;
        scanf("%d %d", &N, &K);
        int arr[N];
        for (int i = 0; i < N; i++) {
            scanf("%d", &arr[i]);
        }
        qsort(arr, N, sizeof(int), compare);
        int sum = 0;
        for (int i = 0; i < N; i++) {
            sum += arr[i];
        }
        if (sum == K) {
            printf("0\n");
        } else if (sum < K) {
            printf("-1\n");
        } else {
            int count = 0;
            for (int i = N - 1; i >= 0; i--) {
                if (sum > K) {
                    sum -= arr[i];
                    count++;
                }
            }
            printf("%d\n", count);
        }
    }
    return 0;
}

